/**
 * Combined ingestion for all 4 German energy regulators.
 *
 * Inserts regulatory content sourced from:
 *   - Bundesnetzagentur (bundesnetzagentur.de) — Beschlusskammer decisions, Festlegungen, Verordnungen
 *   - German TSOs (netztransparenz.de) — VDE-AR-N grid codes, Redispatch 2.0, NEP
 *   - BMWK (bmwk.de) — EnWG, EEG, KWKG, Energiewende policy, hydrogen strategy
 *   - BfE/BASE (base.bund.de) — nuclear safety, Standortauswahlgesetz, repository site selection
 *
 * Sources:
 *   - gesetze-im-internet.de (EnWG, EEG, ARegV, StromNEV, GasNEV, KWKG, WindSeeG, NABEG, EnSiG, etc.)
 *   - bundesnetzagentur.de/DE/Beschlusskammern/ (BK4, BK6, BK7, BK8, BK9 decisions)
 *   - netztransparenz.de / vde.com/fnn (VDE-AR-N standards)
 *   - bmwk.de (policy documents)
 *   - base.bund.de (nuclear regulations)
 *
 * Usage:
 *   npx tsx scripts/ingest-all.ts
 *   npx tsx scripts/ingest-all.ts --force   # drop and recreate
 */

import Database from "better-sqlite3";
import { existsSync, mkdirSync, unlinkSync } from "node:fs";
import { dirname } from "node:path";
import { SCHEMA_SQL } from "../src/db.js";

const DB_PATH = process.env["DE_ENERGY_DB_PATH"] ?? "data/de-energy.db";
const force = process.argv.includes("--force");

const dir = dirname(DB_PATH);
if (!existsSync(dir)) mkdirSync(dir, { recursive: true });
if (force && existsSync(DB_PATH)) {
  unlinkSync(DB_PATH);
  console.log(`Deleted ${DB_PATH}`);
}

const db = new Database(DB_PATH);
db.pragma("journal_mode = WAL");
db.pragma("foreign_keys = ON");
db.exec(SCHEMA_SQL);

// ═══════════════════════════════════════════════════════════════
// REGULATORS
// ═══════════════════════════════════════════════════════════════

const regulators = [
  { id: "bnetza", name: "Bundesnetzagentur", full_name: "Bundesnetzagentur (BNetzA)", url: "https://bundesnetzagentur.de", description: "Bundesoberbehorde im Geschaeftsbereich des BMWK. Regulierung der Strom- und Gasmaerkte, Anreizregulierung, Netzzugang, Netzentgelte, Marktmonitoring, Durchsetzung von EnWG und zugehoerigen Verordnungen. Beschlusskammern: BK4 (Querschnitt Energie), BK6 (Elektrizitaetsnetzzugang), BK7 (Gasnetzzugang/Wasserstoff), BK8 (Netzentgelte Strom), BK9 (Netzentgelte Gas)." },
  { id: "tso", name: "German TSOs", full_name: "German TSOs (50Hertz, Amprion, TenneT DE, TransnetBW)", url: "https://netztransparenz.de", description: "Deutschlands vier Uebertragungsnetzbetreiber. Hochspannungsnetz-Management, VDE-AR-N Netzanschlussregeln, Redispatch 2.0, Netzentwicklungsplan (NEP), Netzanschlussanforderungen, Systemdienstleistungen, Regelenergiemaerkte." },
  { id: "bmwk", name: "BMWK", full_name: "Bundesministerium fuer Wirtschaft und Klimaschutz (BMWK)", url: "https://bmwk.de", description: "Federführendes Ministerium fuer Energiepolitik. Energiewende-Strategie, EnWG, EEG, KWKG, Nationale Wasserstoffstrategie, Kohleausstieg, Klimaschutzprogramm, Energieeffizienz, Waermeplanung, Industriestrompreis." },
  { id: "bfe", name: "BASE", full_name: "Bundesamt fuer die Sicherheit der nuklearen Entsorgung (BASE)", url: "https://base.bund.de", description: "Bundesoberbehorde im Geschaeftsbereich des BMUV. Regulierung des Standortauswahlverfahrens fuer ein Endlager hochradioaktiver Abfaelle, atomrechtliche Genehmigungen fuer Zwischenlager und Transporte, Nuklearsicherheit, Stilllegung." },
];

const insertReg = db.prepare("INSERT OR IGNORE INTO regulators (id, name, full_name, url, description) VALUES (?, ?, ?, ?, ?)");
for (const r of regulators) insertReg.run(r.id, r.name, r.full_name, r.url, r.description);
console.log(`Inserted ${regulators.length} regulators`);

